# Geometry shapes module - imports from math_utils
from math_utils import PI

class Shape:
    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        self.radius = radius

    @override
    def area(self) -> float:
        return PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * PI * self.radius

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)
